    {"id": "inno_sect_217", "name_en": "AI-Driven Drug Discovery", "name_ja": "AI駆動型創薬", "definition": "機械学習・深層学習を活用した標的同定・リード化合物最適化・毒性予測・臨床試験設計の革新。AlphaFoldによるタンパク質構造予測や、生成AIによる新規分子設計が創薬プロセスを根本的に変革する可能性。Insilico Medicine、Recursion等のAIネイティブ企業が台頭。", "impact_summary": "創薬プロセスの効率化と新たな産業構造の形成", "era_start": 2015, "schumpeter_layer": "meso", "key_researchers": ["Alex Zhavoronkov", "Daphne Koller"], "key_works": ["Deep learning for drug discovery (2019)"], "industry_tags": "pharmaceutical, AI, biotechnology", "school_of_thought": "計算創薬論", "innovation_type": "process,product,paradigm", "cognitive_mechanism": "machine_learning,generative", "keywords_en": "AI drug discovery, deep learning, AlphaFold, generative chemistry", "keywords_ja": "AI創薬,深層学習,AlphaFold,生成化学", "opposing_concept_names": "traditional high-throughput screening", "category": "D_directionality"},
    {"id": "inno_sect_218", "name_en": "Cell and Gene Therapy Innovation System", "name_ja": "細胞・遺伝子治療イノベーションシステム", "definition": "CAR-T細胞療法・遺伝子治療等の先端治療法が形成する新たなセクター構造。個別化製造プロセス・高額な治療費・成果ベース償還モデル・サプライチェーンの複雑性という固有の課題が、従来の医薬品産業モデルとは異なるイノベーションシステムを構成。", "impact_summary": "先端治療による医薬品産業の構造変革と新たなビジネスモデル", "era_start": 2012, "schumpeter_layer": "meso", "key_researchers": ["Carl June", "James Wilson"], "key_works": ["Gene therapy clinical trials worldwide (2017)"], "industry_tags": "cell therapy, gene therapy, biotechnology", "school_of_thought": "先端治療産業論", "innovation_type": "product,paradigm", "cognitive_mechanism": "paradigm_shift,personalization", "keywords_en": "cell therapy, gene therapy, CAR-T, personalized manufacturing", "keywords_ja": "細胞治療,遺伝子治療,CAR-T,個別化製造", "opposing_concept_names": "mass-produced pharmaceuticals", "category": "D_directionality"},
    {"id": "inno_sect_219", "name_en": "Global Health Innovation", "name_ja": "グローバルヘルスイノベーション", "definition": "低中所得国における健康課題（感染症・母子保健・栄養）に対するイノベーションの構造的特性。市場インセンティブの欠如・適正技術の必要性・国際的資金メカニズム（GFATM・CEPI等）・南北格差が形成するセクター固有のイノベーションシステム。", "impact_summary": "開発途上国向け医療イノベーションの制度設計", "era_start": 2000, "schumpeter_layer": "macro", "key_researchers": ["Michael Kremer", "Amartya Sen", "Paul Farmer"], "key_works": ["Making markets for vaccines (2004)"], "industry_tags": "global health, vaccines, diagnostics", "school_of_thought": "グローバルヘルス経済学", "innovation_type": "institutional,product", "cognitive_mechanism": "inclusive_innovation,frugal", "keywords_en": "global health innovation, neglected diseases, access to medicine, GFATM", "keywords_ja": "グローバルヘルスイノベーション,顧みられない疾患,医薬品アクセス", "opposing_concept_names": "high-income market-driven innovation", "category": "D_directionality"},
    {"id": "inno_sect_220", "name_en": "Telemedicine Adoption Dynamics", "name_ja": "遠隔医療普及動態", "definition": "遠隔医療の採用・普及を規定するセクター固有要因。(1)規制・償還制度の制約、(2)臨床的有効性のエビデンス蓄積、(3)医療専門職の技術受容性、(4)患者の利用意向・デジタルリテラシー、(5)医療格差是正の政策的要請。COVID-19が強制的普及実験として機能し、構造的転換点を形成。", "impact_summary": "遠隔医療の構造的障壁と促進要因の多層的理解", "era_start": 2005, "schumpeter_layer": "meso", "key_researchers": ["Rashid Bashshur", "Charles Doarn"], "key_works": ["Telemedicine and e-health policy and practice (2012)"], "industry_tags": "telemedicine, digital health, healthcare", "school_of_thought": "遠隔医療政策論", "innovation_type": "service,institutional", "cognitive_mechanism": "adoption,institutional_change", "keywords_en": "telemedicine, telehealth, remote care, COVID-19 acceleration", "keywords_ja": "遠隔医療,テレヘルス,リモートケア,COVID-19加速", "opposing_concept_names": "in-person care primacy", "category": "D_directionality"},
    {"id": "inno_sect_221", "name_en": "Pharmaceutical Open Innovation", "name_ja": "製薬オープンイノベーション", "definition": "製薬産業における外部知識の戦略的活用。自社R&Dの限界を補完するため、アカデミア連携・ベンチャー投資・プレコンペティティブ研究コンソーシアム・クラウドソーシング等の多様なオープンイノベーション形態が発展。Eli Lillyの InnoCentive、AstraZenecaのオープンイノベーションプラットフォーム等が先駆例。", "impact_summary": "製薬R&Dの外部化と知識ネットワークの構造変革", "era_start": 2006, "schumpeter_layer": "meso", "key_researchers": ["Henry Chesbrough", "Gary Pisano", "Markus Nordberg"], "key_works": ["Open innovation in the pharmaceutical industry (2014)"], "industry_tags": "pharmaceutical, biotechnology", "school_of_thought": "製薬オープンイノベーション論", "innovation_type": "organizational,process", "cognitive_mechanism": "open_innovation,network", "keywords_en": "pharmaceutical open innovation, precompetitive collaboration, crowdsourcing", "keywords_ja": "製薬オープンイノベーション,プレコンペティティブ,クラウドソーシング", "opposing_concept_names": "closed pharma R&D model", "category": "D_directionality"},
    {"id": "inno_sect_222", "name_en": "Healthcare Service Innovation", "name_ja": "医療サービスイノベーション", "definition": "医療提供体制におけるサービスプロセス革新。リーン医療・患者中心ケア・統合ケアモデル・バリューベースヘルスケア等、製造業とは異なるサービス固有のイノベーション特性。専門職主義・規制制約・患者安全要求がイノベーション動態を規定。", "impact_summary": "医療のサービス産業としてのイノベーション特性の理論化", "era_start": 2006, "schumpeter_layer": "meso", "key_researchers": ["Michael Porter", "Elizabeth Teisberg"], "key_works": ["Redefining health care: creating value-based competition on results (2006)"], "industry_tags": "healthcare, hospitals, primary care", "school_of_thought": "医療サービス革新論", "innovation_type": "service,process", "cognitive_mechanism": "value_creation,lean", "keywords_en": "healthcare service innovation, value-based care, lean healthcare, patient-centered", "keywords_ja": "医療サービスイノベーション,バリューベースケア,リーン医療", "opposing_concept_names": "volume-based care model", "category": "D_directionality"},
    {"id": "inno_sect_223", "name_en": "Pharmaceutical Cluster Dynamics", "name_ja": "製薬クラスター動態", "definition": "製薬・バイオテクノロジー企業の地理的集積（Boston/Cambridge、San Francisco Bay Area、Basel等）がイノベーション性能に与える効果。スピルオーバー・労働市場プール・ベンチャーキャピタル近接性・アカデミア連携の地理的優位性が集積のメカニズム。", "impact_summary": "製薬イノベーションの地理的決定要因の解明", "era_start": 2000, "schumpeter_layer": "meso", "key_researchers": ["Maryann Feldman", "Olav Sorenson", "Michael Porter"], "key_works": ["The geography of innovation: regional innovation systems (2005)"], "industry_tags": "pharmaceutical, biotechnology, research clusters", "school_of_thought": "イノベーション地理学", "innovation_type": "organizational,systemic", "cognitive_mechanism": "agglomeration,spillover", "keywords_en": "pharmaceutical cluster, biotech hub, agglomeration, knowledge spillover", "keywords_ja": "製薬クラスター,バイオテクハブ,集積効果,知識スピルオーバー", "opposing_concept_names": "distributed innovation model", "category": "D_directionality"},
    {"id": "inno_sect_224", "name_en": "Real-World Evidence in Healthcare", "name_ja": "リアルワールドエビデンス", "definition": "電子健康記録（EHR）・保険請求データ・患者レジストリ等の実臨床データから得られるエビデンスの活用。RCTの限界を補完し、医薬品の有効性・安全性の市販後評価、適応拡大、規制意思決定を支援。21世紀治療法（21st Century Cures Act）により制度化が進展。", "impact_summary": "医薬品評価のエビデンス基盤の拡大と規制パラダイムの変革", "era_start": 2012, "schumpeter_layer": "meso", "key_researchers": ["Sebastian Schneeweiss", "Robert Califf"], "key_works": ["Real-world evidence: what is it and what can it tell us? (2017)"], "industry_tags": "pharmaceutical, healthcare, data analytics", "school_of_thought": "リアルワールドエビデンス論", "innovation_type": "process,institutional", "cognitive_mechanism": "data_driven,pragmatic", "keywords_en": "real-world evidence, RWE, electronic health records, post-market surveillance", "keywords_ja": "リアルワールドエビデンス,RWE,電子健康記録,市販後調査", "opposing_concept_names": "RCT-only evidence paradigm", "category": "D_directionality"},
    {"id": "inno_sect_225", "name_en": "Antimicrobial Resistance Innovation Challenge", "name_ja": "薬剤耐性イノベーション課題", "definition": "抗菌薬耐性（AMR）問題における市場の失敗と創薬イノベーションの構造的課題。新規抗菌薬の低い投資収益率・使用制限による売上制約・短い治療期間がR&Dインセンティブを著しく毀損。プッシュ・プルインセンティブの組み合わせ（CARB-X、BARDA等）による解決が模索される。", "impact_summary": "抗菌薬開発の市場失敗と公的介入メカニズムの設計", "era_start": 2010, "schumpeter_layer": "meso", "key_researchers": ["Jim O'Neill", "Kevin Outterson"], "key_works": ["Tackling drug-resistant infections globally (O'Neill Review, 2016)"], "industry_tags": "pharmaceutical, antimicrobials, public health", "school_of_thought": "AMR政策論", "innovation_type": "institutional,product", "cognitive_mechanism": "market_failure,incentive_design", "keywords_en": "antimicrobial resistance, AMR, antibiotic pipeline, push-pull incentives", "keywords_ja": "薬剤耐性,AMR,抗菌薬パイプライン,プッシュプルインセンティブ", "opposing_concept_names": "market-sufficient antibiotic development", "category": "D_directionality"},
    {"id": "inno_sect_226", "name_en": "Surgical Innovation Diffusion", "name_ja": "外科イノベーション普及", "definition": "手術手技・機器の開発・普及における固有の動態。(1)術者の学習曲線が普及速度を制約、(2)RCTの実施困難性、(3)ロボット支援手術等の資本集約的技術、(4)ギルド的職能文化がイノベーション動態に影響。外科専門学会が技術評価・教育の重要な媒介機能を果たす。", "impact_summary": "外科領域固有のイノベーション普及メカニズムの理解", "era_start": 2002, "schumpeter_layer": "meso", "key_researchers": ["Ara Darzi", "Peter McCulloch"], "key_works": ["Surgical innovation and evaluation (IDEAL framework, 2009)"], "industry_tags": "surgery, medical devices, robotics", "school_of_thought": "外科イノベーション論", "innovation_type": "process,product", "cognitive_mechanism": "learning_curve,craft_knowledge", "keywords_en": "surgical innovation, IDEAL framework, learning curve, robotic surgery", "keywords_ja": "外科イノベーション,IDEAL枠組み,学習曲線,ロボット手術", "opposing_concept_names": "evidence-only adoption model", "category": "D_directionality"},
    {"id": "inno_sect_227", "name_en": "Pharmaceutical Value Chain Restructuring", "name_ja": "医薬品バリューチェーン再構築", "definition": "CRO（受託研究機関）・CDMO（受託開発製造機関）の台頭による医薬品産業のバリューチェーン分解と再統合。垂直統合型モデルからネットワーク型モデルへの移行が、R&D効率・製造柔軟性・市場投入速度に与える影響を分析。", "impact_summary": "医薬品産業の垂直分業化と産業構造変革の理解", "era_start": 2005, "schumpeter_layer": "meso", "key_researchers": ["Ashish Arora", "Andrea Fosfuri"], "key_works": ["Markets for technology: the economics of innovation and corporate strategy (2001)"], "industry_tags": "pharmaceutical, CRO, CDMO", "school_of_thought": "医薬品産業組織論", "innovation_type": "organizational,process", "cognitive_mechanism": "value_chain,modularization", "keywords_en": "pharmaceutical value chain, CRO, CDMO, outsourcing, virtual pharma", "keywords_ja": "医薬品バリューチェーン,CRO,CDMO,アウトソーシング", "opposing_concept_names": "vertically integrated pharma model", "category": "D_directionality"},
    {"id": "inno_sect_228", "name_en": "Mental Health Innovation Gap", "name_ja": "精神医療イノベーションギャップ", "definition": "精神疾患治療におけるイノベーションの構造的停滞。(1)疾患メカニズムの複雑性、(2)動物モデルの妥当性欠如、(3)臨床エンドポイントの主観性、(4)スティグマによる研究投資不足が複合的に作用し、1990年代以降の新規作用機序薬剤の枯渇を招いた。近年のケタミン・サイロシビン研究が新たな展開。", "impact_summary": "精神医療領域のイノベーション停滞要因と打開策の分析", "era_start": 2010, "schumpeter_layer": "meso", "key_researchers": ["Thomas Insel", "Steven Hyman"], "key_works": ["Disruptive insights in psychiatry (2012)"], "industry_tags": "pharmaceutical, mental health, neuroscience", "school_of_thought": "精神医療イノベーション論", "innovation_type": "product,scientific", "cognitive_mechanism": "paradigm_crisis,translational_gap", "keywords_en": "mental health innovation, neuroscience, psychedelic therapy, innovation gap", "keywords_ja": "精神医療イノベーション,神経科学,サイケデリック療法", "opposing_concept_names": "incremental pharmaceutical innovation", "category": "D_directionality"},
    {"id": "inno_sect_229", "name_en": "Point-of-Care Diagnostics Innovation", "name_ja": "ポイントオブケア診断イノベーション", "definition": "臨床現場（ベッドサイド・外来・在宅）で即座に結果が得られる診断技術のイノベーション。マイクロフルイディクス・バイオセンサー・AI画像診断の収束により、検査室中心モデルからの分散化が進行。特にリソース制約環境（低中所得国）での適正技術としての重要性。", "impact_summary": "診断技術の分散化と医療アクセス改善の基盤", "era_start": 2005, "schumpeter_layer": "meso", "key_researchers": ["George Whitesides", "Paul Yager"], "key_works": ["Diagnostics for the developing world (2006)"], "industry_tags": "diagnostics, medical devices, global health", "school_of_thought": "診断技術革新論", "innovation_type": "product,process", "cognitive_mechanism": "miniaturization,frugal_innovation", "keywords_en": "point-of-care diagnostics, microfluidics, biosensor, rapid test", "keywords_ja": "ポイントオブケア診断,マイクロフルイディクス,バイオセンサー", "opposing_concept_names": "centralized laboratory model", "category": "D_directionality"},
    {"id": "inno_sect_230", "name_en": "Health Data Platform Economy", "name_ja": "ヘルスデータプラットフォーム経済", "definition": "健康・医療データの大規模収集・解析基盤がセクターの競争構造を変革するメカニズム。GAFAM・大手保険会社・テック系スタートアップの参入により、データプラットフォームが新たな競争軸に。プライバシー・データ主権・相互運用性の制度的課題が発展を規定。", "impact_summary": "ヘルスケア産業におけるデータ駆動型競争構造の形成", "era_start": 2015, "schumpeter_layer": "meso", "key_researchers": ["Eric Topol", "John Halamka"], "key_works": ["Deep medicine (2019)"], "industry_tags": "digital health, health data, platform", "school_of_thought": "ヘルスケアプラットフォーム論", "innovation_type": "service,platform", "cognitive_mechanism": "platform,data_driven", "keywords_en": "health data platform, digital health ecosystem, interoperability, data governance", "keywords_ja": "ヘルスデータプラットフォーム,デジタルヘルスエコシステム,相互運用性", "opposing_concept_names": "fragmented health data systems", "category": "D_directionality"},
    {"id": "inno_sect_231", "name_en": "Nursing Innovation and Practice Change", "name_ja": "看護イノベーションと実践変革", "definition": "看護専門職によるケアプロセス・デリバリーモデルの革新。エビデンスベースド看護実践・ナースプラクティショナー制度・テクノロジー活用看護の進化が、医療サービスイノベーションの重要な駆動力。専門職の自律性と制度的制約の緊張関係がイノベーション動態を形成。", "impact_summary": "看護職主導の医療サービス革新の理論的基盤", "era_start": 2000, "schumpeter_layer": "micro", "key_researchers": ["Patricia Benner", "Linda Aiken"], "key_works": ["From novice to expert (1984)", "Hospital nurse staffing and patient mortality (2002)"], "industry_tags": "nursing, healthcare, hospitals", "school_of_thought": "看護イノベーション論", "innovation_type": "process,service", "cognitive_mechanism": "professional_autonomy,practice_based", "keywords_en": "nursing innovation, evidence-based nursing, nurse practitioner, care delivery", "keywords_ja": "看護イノベーション,エビデンスベースド看護,ナースプラクティショナー", "opposing_concept_names": "physician-centric innovation model", "category": "D_directionality"},
    {"id": "inno_sect_232", "name_en": "Medical Imaging Innovation Trajectory", "name_ja": "医用画像イノベーション軌道", "definition": "X線・CT・MRI・PET・超音波等の医用画像技術の進化軌道。科学的発見→工学的実装→臨床応用→規制承認→保険償還の長期的プロセスが特徴。AI画像診断の統合により新たな技術パラダイムが形成。大規模資本投資と専門知識の累積性がセクター構造を規定。", "impact_summary": "医用画像セクターの技術進化パターンと産業構造の理解", "era_start": 1990, "schumpeter_layer": "meso", "key_researchers": ["Rebecca Henderson", "Kim Clark"], "key_works": ["Architectural innovation in diagnostic imaging (1990)"], "industry_tags": "medical imaging, radiology, AI diagnostics", "school_of_thought": "医用画像技術進化論", "innovation_type": "product,process", "cognitive_mechanism": "architectural,cumulative", "keywords_en": "medical imaging, CT, MRI, AI radiology, imaging technology trajectory", "keywords_ja": "医用画像,CT,MRI,AI放射線学,画像技術軌道", "opposing_concept_names": "clinical judgment-only diagnosis", "category": "D_directionality"},
    {"id": "inno_sect_233", "name_en": "Patient Innovation and Self-Care", "name_ja": "患者イノベーションとセルフケア", "definition": "患者自身がイノベーターとして疾患管理・治療法・支援技術を開発するユーザーイノベーション。希少疾患コミュニティ・患者団体・DIYバイオハッキングコミュニティが自発的に技術開発・知識共有を行う。制度的認知は不十分だが、医療イノベーションシステムへの寄与は大きい。", "impact_summary": "患者主導型イノベーションの認識と制度的支援の理論的根拠", "era_start": 2012, "schumpeter_layer": "micro", "key_researchers": ["Pedro Oliveira", "Eric von Hippel"], "key_works": ["Users as service innovators: the case of banking services (2012)"], "industry_tags": "healthcare, patient advocacy, rare diseases", "school_of_thought": "患者イノベーション論", "innovation_type": "product,process,user", "cognitive_mechanism": "user_innovation,community", "keywords_en": "patient innovation, user innovation, self-care technology, rare disease community", "keywords_ja": "患者イノベーション,ユーザーイノベーション,セルフケア技術", "opposing_concept_names": "professional-only innovation model", "category": "D_directionality"},
    {"id": "inno_sect_234", "name_en": "Hospital-Acquired Infection Prevention Innovation", "name_ja": "院内感染予防イノベーション", "definition": "医療関連感染（HAI）対策のプロセスイノベーション。チェックリスト導入・手指衛生強化・環境消毒技術・抗菌素材の統合的アプローチ。Peter Pronovostのチェックリスト研究が示すように、組織的行動変容が技術革新以上にインパクトを持つセクター固有の特性。", "impact_summary": "医療安全におけるプロセス革新の有効性実証", "era_start": 2004, "schumpeter_layer": "micro", "key_researchers": ["Peter Pronovost", "Didier Pittet"], "key_works": ["An intervention to decrease catheter-related bloodstream infections (2006)"], "industry_tags": "healthcare, infection control, hospital safety", "school_of_thought": "医療安全イノベーション論", "innovation_type": "process,organizational", "cognitive_mechanism": "behavioral_change,systematic", "keywords_en": "hospital-acquired infection, patient safety, checklist, hand hygiene", "keywords_ja": "院内感染,患者安全,チェックリスト,手指衛生", "opposing_concept_names": "technology-only solution approach", "category": "D_directionality"},
    {"id": "inno_sect_235", "name_en": "Pharmaceutical Pricing Innovation", "name_ja": "医薬品価格設定イノベーション", "definition": "価値ベース価格設定・成果連動型契約・サブスクリプションモデル等、従来のコストプラス型から脱却する医薬品価格設定の制度的イノベーション。高額治療薬の増加に伴い、支払者・製薬企業・患者間のリスク分担メカニズムが発展。", "impact_summary": "医薬品アクセスと産業持続可能性の両立メカニズム", "era_start": 2010, "schumpeter_layer": "meso", "key_researchers": ["Adrian Towse", "Peter Bach"], "key_works": ["Value-based pricing for pharmaceuticals (2010)"], "industry_tags": "pharmaceutical, health economics, payer", "school_of_thought": "医薬品価値評価論", "innovation_type": "institutional,market", "cognitive_mechanism": "value_based,outcome_linked", "keywords_en": "pharmaceutical pricing, value-based pricing, outcomes-based contracts, subscription model", "keywords_ja": "医薬品価格設定,価値ベース価格,成果連動型契約", "opposing_concept_names": "cost-plus pricing model", "category": "D_directionality"},
    {"id": "inno_sect_236", "name_en": "Regenerative Medicine Industry Formation", "name_ja": "再生医療産業形成", "definition": "iPS細胞・幹細胞技術・組織工学に基づく再生医療産業の創出プロセス。科学的ブレークスルーから産業化までの長期的な制度構築（規制整備・製造標準化・保険適用）が必要。日本の再生医療新法（2014年）は先駆的制度設計の一例。", "impact_summary": "新興医療産業の制度的基盤構築の理解", "era_start": 2006, "schumpeter_layer": "meso", "key_researchers": ["Shinya Yamanaka", "Robert Langer"], "key_works": ["Induction of pluripotent stem cells from mouse embryonic and adult fibroblasts (2006)"], "industry_tags": "regenerative medicine, stem cells, tissue engineering", "school_of_thought": "再生医療産業論", "innovation_type": "product,institutional", "cognitive_mechanism": "science_push,institution_building", "keywords_en": "regenerative medicine, iPS cells, stem cells, tissue engineering, industry formation", "keywords_ja": "再生医療,iPS細胞,幹細胞,組織工学,産業形成", "opposing_concept_names": "conventional pharmaceutical approach", "category": "D_directionality"},
    {"id": "inno_sect_237", "name_en": "Elderly Care Technology Innovation", "name_ja": "高齢者介護テクノロジーイノベーション", "definition": "超高齢社会における介護ロボット・見守りシステム・認知症支援技術等のイノベーション。技術的可能性と社会的受容性のギャップ、低賃金労働市場における代替インセンティブの弱さ、倫理的課題が普及動態を複雑にする。日本がリードするセクター。", "impact_summary": "高齢者ケアにおける技術イノベーションの社会技術的課題の理解", "era_start": 2008, "schumpeter_layer": "meso", "key_researchers": ["Hiroshi Ishiguro", "Takanori Shibata"], "key_works": ["Robots for elderly care (2012)"], "industry_tags": "elderly care, assistive technology, robotics", "school_of_thought": "介護テクノロジー論", "innovation_type": "product,service", "cognitive_mechanism": "sociotechnical,acceptance", "keywords_en": "elderly care technology, care robots, assistive technology, aging society", "keywords_ja": "高齢者介護技術,介護ロボット,支援技術,高齢化社会", "opposing_concept_names": "human-only care model", "category": "D_directionality"},
    {"id": "inno_sect_238", "name_en": "Pharmaceutical M&A as Innovation Strategy", "name_ja": "製薬M&Aイノベーション戦略", "definition": "大手製薬企業がパイプライン補充・技術獲得・市場拡大を目的としてM&Aを活用するイノベーション戦略。内部R&Dの生産性低下に対応する外部化戦略として、2000年代以降の大型合併・バイオテック買収ラッシュが産業構造を再編。買収後統合（PMI）の成否が戦略的成果を左右。", "impact_summary": "製薬産業の統合動態とイノベーション効率への影響の理解", "era_start": 2000, "schumpeter_layer": "meso", "key_researchers": ["Patricia Danzon", "Andrew Epstein", "Sean Nicholson"], "key_works": ["Mergers and acquisitions in the pharmaceutical and biotech industries (2007)"], "industry_tags": "pharmaceutical, M&A, biotechnology", "school_of_thought": "製薬産業再編論", "innovation_type": "organizational,market", "cognitive_mechanism": "acquisition,consolidation", "keywords_en": "pharmaceutical M&A, pipeline acquisition, post-merger integration, biotech acquisition", "keywords_ja": "製薬M&A,パイプライン買収,買収後統合", "opposing_concept_names": "organic growth R&D model", "category": "D_directionality"},
    {"id": "inno_sect_239", "name_en": "Global Pharmaceutical Supply Chain Innovation", "name_ja": "グローバル医薬品サプライチェーンイノベーション", "definition": "医薬品のグローバル製造・流通における品質管理・トレーサビリティ・コールドチェーンのイノベーション。偽造薬対策（シリアライゼーション）、COVID-19が顕在化させたサプライチェーン脆弱性、APIの地理的集中リスクへの対応が駆動力。", "impact_summary": "医薬品サプライチェーンのレジリエンスと品質保証の革新", "era_start": 2010, "schumpeter_layer": "meso", "key_researchers": ["Prashant Yadav", "Yossi Sheffi"], "key_works": ["Pharmaceutical supply chains: key issues and strategies for optimisation (2016)"], "industry_tags": "pharmaceutical, supply chain, logistics", "school_of_thought": "医薬品サプライチェーン論", "innovation_type": "process,organizational", "cognitive_mechanism": "resilience,traceability", "keywords_en": "pharmaceutical supply chain, serialization, cold chain, API sourcing", "keywords_ja": "医薬品サプライチェーン,シリアライゼーション,コールドチェーン", "opposing_concept_names": "just-in-time lean supply chain", "category": "D_directionality"},
    {"id": "inno_sect_240", "name_en": "Clinical Decision Support Innovation", "name_ja": "臨床意思決定支援イノベーション", "definition": "電子カルテ統合型の臨床意思決定支援システム（CDSS）のイノベーション。アラート疲労・ワークフロー統合・AI予測モデルの活用という3つの課題軸が技術発展を規定。処方支援・診断支援・治療推奨の自動化がセクターの知識活用を変革。", "impact_summary": "臨床情報学におけるAI活用と医療意思決定の革新", "era_start": 2005, "schumpeter_layer": "micro", "key_researchers": ["Robert Greenes", "Adam Wright"], "key_works": ["Clinical decision support systems: theory and practice (2007)"], "industry_tags": "health IT, clinical informatics, hospitals", "school_of_thought": "臨床情報学", "innovation_type": "process,product", "cognitive_mechanism": "decision_support,automation", "keywords_en": "clinical decision support, CDSS, alert fatigue, EHR integration, AI diagnostics", "keywords_ja": "臨床意思決定支援,CDSS,アラート疲労,電子カルテ統合", "opposing_concept_names": "unaided clinical judgment", "category": "D_directionality"},
    {"id": "inno_sect_241", "name_en": "Dental Innovation System", "name_ja": "歯科イノベーションシステム", "definition": "歯科領域のイノベーション固有特性。(1)分散的な個人開業医構造、(2)材料科学主導の技術進歩、(3)CAD/CAMデジタル歯科の普及、(4)予防歯科への転換。小規模事業体が支配的な産業構造がイノベーション普及パターンを規定。", "impact_summary": "歯科セクターのデジタル変革とイノベーション動態の理解", "era_start": 2005, "schumpeter_layer": "meso", "key_researchers": ["Florian."," 2016"], "key_works": ["Digital dentistry: an overview (2017)"], "industry_tags": "dentistry, dental materials, CAD/CAM", "school_of_thought": "歯科イノベーション論", "innovation_type": "product,process", "cognitive_mechanism": "digital_transformation,material_science", "keywords_en": "dental innovation, CAD/CAM dentistry, digital workflow, dental materials", "keywords_ja": "歯科イノベーション,CAD/CAM歯科,デジタルワークフロー", "opposing_concept_names": "traditional analog dentistry", "category": "D_directionality"},
    {"id": "inno_sect_242", "name_en": "Pharmaceutical Intellectual Property Strategy", "name_ja": "医薬品知的財産戦略", "definition": "医薬品産業における特許戦略・データ独占権・商標戦略の複合的イノベーション保護メカニズム。パテントクラスタリング・エバーグリーニング・REMS独占等の戦略的行動が競争構造とジェネリック参入タイミングを規定。Hatch-Waxman法の枠組みが米国市場の構造的基盤。", "impact_summary": "医薬品の知財戦略と市場競争構造の関係の理解", "era_start": 1984, "schumpeter_layer": "meso", "key_researchers": ["Robin Feldman", "Arti Rai"], "key_works": ["May your drug price be evergreen (2018)"], "industry_tags": "pharmaceutical, intellectual property, patent law", "school_of_thought": "医薬品知財論", "innovation_type": "institutional,strategic", "cognitive_mechanism": "appropriability,strategic", "keywords_en": "pharmaceutical IP, patent strategy, evergreening, data exclusivity, Hatch-Waxman", "keywords_ja": "医薬品知財,特許戦略,エバーグリーニング,データ独占権", "opposing_concept_names": "open-source drug development", "category": "D_directionality"},
    {"id": "inno_sect_243", "name_en": "Wearable Health Monitoring Innovation", "name_ja": "ウェアラブル健康モニタリングイノベーション", "definition": "Apple Watch・Fitbit等のウェアラブルデバイスによる継続的健康モニタリングの革新。消費者向け技術と医療グレードの境界融解が進行。心電図・血中酸素・心房細動検出等の機能追加により、セルフケアと臨床介入の接続が実現しつつある。FDA/MDR等の規制適応が進展課題。", "impact_summary": "消費者ヘルステクノロジーと医療の融合メカニズムの理解", "era_start": 2014, "schumpeter_layer": "meso", "key_researchers": ["Eric Topol", "Steven Steinhubl"], "key_works": ["Novel approaches to monitoring and management of health (2018)"], "industry_tags": "wearables, digital health, consumer electronics", "school_of_thought": "ウェアラブルヘルス論", "innovation_type": "product,service", "cognitive_mechanism": "convergence,consumer_driven", "keywords_en": "wearable health monitoring, Apple Watch, continuous monitoring, consumer health", "keywords_ja": "ウェアラブル健康モニタリング,継続的モニタリング,消費者ヘルス", "opposing_concept_names": "episodic clinical monitoring", "category": "D_directionality"},
    {"id": "inno_sect_244", "name_en": "Pharmaceutical Sustainability Innovation", "name_ja": "製薬サステナビリティイノベーション", "definition": "医薬品産業の環境負荷低減に向けたグリーンケミストリー・プロセス効率化・サプライチェーン持続可能性のイノベーション。化学合成の溶媒削減・連続フロー製造・バイオ触媒の活用が環境効率性と経済効率性を同時に改善。ESG投資圧力が推進力。", "impact_summary": "製薬産業の持続可能性転換と環境イノベーションの推進", "era_start": 2010, "schumpeter_layer": "meso", "key_researchers": ["Roger Sheldon", "John Warner"], "key_works": ["Green chemistry in the pharmaceutical industry (2010)"], "industry_tags": "pharmaceutical, green chemistry, sustainability", "school_of_thought": "グリーンファーマ論", "innovation_type": "process,organizational", "cognitive_mechanism": "sustainability,efficiency", "keywords_en": "green pharmacy, sustainable manufacturing, continuous flow, biocatalysis, ESG", "keywords_ja": "グリーンファーマ,持続可能製造,連続フロー,バイオ触媒", "opposing_concept_names": "traditional batch manufacturing", "category": "D_directionality"},
    {"id": "inno_sect_245", "name_en": "Rare Disease Innovation Ecosystem", "name_ja": "希少疾患イノベーションエコシステム", "definition": "希少疾患治療における患者団体・研究者・バイオテック・規制当局・資金提供者の協働エコシステム。患者レジストリの構築・自然歴研究・患者参加型研究デザインが、小規模患者集団でのエビデンス構築を可能にする。患者団体がイノベーションの推進者として独自の役割を担う。", "impact_summary": "希少疾患領域の多ステークホルダー型イノベーション推進モデル", "era_start": 2008, "schumpeter_layer": "meso", "key_researchers": ["Sharon Terry", "Austin Regan"], "key_works": ["Patient-centered approaches to rare disease research (2015)"], "industry_tags": "rare diseases, patient advocacy, biotechnology", "school_of_thought": "希少疾患エコシステム論", "innovation_type": "institutional,organizational", "cognitive_mechanism": "ecosystem,patient_driven", "keywords_en": "rare disease ecosystem, patient registry, patient advocacy, natural history study", "keywords_ja": "希少疾患エコシステム,患者レジストリ,患者アドボカシー", "opposing_concept_names": "industry-led drug development", "category": "D_directionality"},
    {"id": "inno_sect_246", "name_en": "Healthcare Blockchain Applications", "name_ja": "医療ブロックチェーン応用", "definition": "分散型台帳技術の医療セクター応用。電子健康記録の相互運用性・臨床試験データの完全性・医薬品サプライチェーントレーサビリティ・保険請求処理の効率化等の用途。技術的成熟度と制度的受容性のギャップが実装速度を制約する典型例。", "impact_summary": "医療データ管理におけるブロックチェーン技術の可能性と限界", "era_start": 2016, "schumpeter_layer": "meso", "key_researchers": ["John Halamka", "Ariel Ekblaw"], "key_works": ["A case study for blockchain in healthcare (2016)"], "industry_tags": "health IT, blockchain, data management", "school_of_thought": "医療ブロックチェーン論", "innovation_type": "process,infrastructure", "cognitive_mechanism": "distributed,trust_architecture", "keywords_en": "healthcare blockchain, distributed ledger, data interoperability, supply chain", "keywords_ja": "医療ブロックチェーン,分散型台帳,データ相互運用性", "opposing_concept_names": "centralized database approach", "category": "D_directionality"},
    {"id": "inno_sect_247", "name_en": "Pharmaceutical Emerging Market Innovation", "name_ja": "新興国医薬品イノベーション", "definition": "インド・中国・ブラジル等の新興国における医薬品産業のキャッチアップ型イノベーション。ジェネリック製造能力の構築から自主的創薬能力の獲得へと進化するプロセス。逆イノベーション（新興国発→先進国へ）の事例も増加。規制調和・知財制度・人材育成が発展の制約要因。", "impact_summary": "新興国医薬品産業の発展経路とグローバル産業構造変化", "era_start": 2005, "schumpeter_layer": "macro", "key_researchers": ["Sudip Chaudhuri", "Fabio Pammolli"], "key_works": ["The Indian pharmaceutical industry (2005)"], "industry_tags": "pharmaceutical, emerging markets, generic drugs", "school_of_thought": "新興国産業発展論", "innovation_type": "product,institutional", "cognitive_mechanism": "catch_up,reverse_innovation", "keywords_en": "emerging market pharma, India generics, catch-up innovation, reverse innovation", "keywords_ja": "新興国医薬品,インドジェネリック,キャッチアップ,逆イノベーション", "opposing_concept_names": "developed country innovation monopoly", "category": "D_directionality"},
    {"id": "inno_sect_248", "name_en": "Genomic Medicine Implementation", "name_ja": "ゲノム医療実装", "definition": "ゲノム解析技術（次世代シーケンサー等）の臨床実装プロセス。技術コスト低下と臨床的有用性のエビデンス蓄積により、がんゲノムプロファイリング・薬理ゲノミクス・出生前遺伝学検査等が普及。医療従事者の教育・倫理的課題・保険適用の制度整備が実装の鍵。", "impact_summary": "ゲノム技術の臨床翻訳と実装科学の理論的基盤", "era_start": 2010, "schumpeter_layer": "meso", "key_researchers": ["Eric Green", "Teri Manolio"], "key_works": ["Charting a course for genomic medicine (2011)"], "industry_tags": "genomics, diagnostics, personalized medicine", "school_of_thought": "ゲノム医療実装論", "innovation_type": "product,process", "cognitive_mechanism": "implementation_science,translation", "keywords_en": "genomic medicine, NGS, cancer genomics, pharmacogenomics, implementation", "keywords_ja": "ゲノム医療,次世代シーケンサー,がんゲノミクス,薬理ゲノミクス", "opposing_concept_names": "one-gene-at-a-time diagnostics", "category": "D_directionality"},
    {"id": "inno_sect_249", "name_en": "Public Health Surveillance Innovation", "name_ja": "公衆衛生サーベイランスイノベーション", "definition": "疾病監視システムのデジタル革新。ゲノムサーベイランス・下水疫学・モバイルデータ解析・AI予測モデルの統合により、感染症アウトブレイクの早期検知能力が飛躍的に向上。COVID-19パンデミックが技術開発・制度整備の大幅な加速装置として機能。", "impact_summary": "感染症監視の技術革新とパンデミック対応能力の向上", "era_start": 2005, "schumpeter_layer": "macro", "key_researchers": ["Larry Brilliant", "Jennifer Gardy"], "key_works": ["Genomic epidemiology: big-data-driven approaches to infectious disease (2014)"], "industry_tags": "public health, epidemiology, surveillance technology", "school_of_thought": "デジタル疫学", "innovation_type": "process,systemic", "cognitive_mechanism": "surveillance,predictive", "keywords_en": "public health surveillance, genomic surveillance, wastewater epidemiology, AI prediction", "keywords_ja": "公衆衛生サーベイランス,ゲノムサーベイランス,下水疫学", "opposing_concept_names": "traditional passive surveillance", "category": "D_directionality"},
    {"id": "inno_sect_250", "name_en": "3D Bioprinting in Healthcare", "name_ja": "医療3Dバイオプリンティング", "definition": "3D印刷技術を活用した医療デバイス・インプラント・組織・臓器の製造イノベーション。個別化インプラント・手術計画モデル・バイオプリンティング（生体組織製造）の3段階で進化。規制枠組みの整備と品質保証が実用化の制約要因。", "impact_summary": "個別化医療製造の技術的可能性と産業的課題の理解", "era_start": 2010, "schumpeter_layer": "meso", "key_researchers": ["Anthony Atala", "Jennifer Lewis"], "key_works": ["3D bioprinting for organ fabrication (2014)"], "industry_tags": "3D printing, medical devices, tissue engineering", "school_of_thought": "バイオプリンティング論", "innovation_type": "product,process", "cognitive_mechanism": "additive_manufacturing,personalization", "keywords_en": "3D bioprinting, personalized implants, tissue engineering, additive manufacturing", "keywords_ja": "3Dバイオプリンティング,個別化インプラント,組織工学", "opposing_concept_names": "mass-produced medical devices", "category": "D_directionality"},
    {"id": "inno_sect_251", "name_en": "Health Insurance Innovation", "name_ja": "医療保険イノベーション", "definition": "医療保険のプロダクト・プロセスイノベーション。バリューベース保険設計・テレマティクス・ヘルスケアナビゲーション・AIリスク評価等により、保険機能が単なる支払者からヘルスケア価値創造の積極的参加者へと進化。規制環境の差異が国・地域間のイノベーション動態を規定。", "impact_summary": "医療保険のイノベーション主体としての役割の進化", "era_start": 2008, "schumpeter_layer": "meso", "key_researchers": ["Michael Chernew", "A. Mark Fendrick"], "key_works": ["Value-based insurance design (2008)"], "industry_tags": "health insurance, payer, insurtech", "school_of_thought": "医療保険イノベーション論", "innovation_type": "service,institutional", "cognitive_mechanism": "value_based,behavioral", "keywords_en": "health insurance innovation, value-based insurance design, insurtech, AI risk", "keywords_ja": "医療保険イノベーション,バリューベース保険設計,インシュアテック", "opposing_concept_names": "traditional fee-for-service insurance", "category": "D_directionality"},
    {"id": "inno_sect_252", "name_en": "Microbiome Therapeutics", "name_ja": "マイクロバイオーム治療薬", "definition": "ヒトマイクロバイオーム（腸内細菌叢等）を標的とする新たな治療アプローチ。糞便移植・生きた微生物製剤（live biotherapeutics）・プレバイオティクス・ポストバイオティクスの開発が進行。規制カテゴリーの未確立、臨床試験設計の困難さが産業化の障壁。", "impact_summary": "マイクロバイオーム産業の形成と新たな治療パラダイム", "era_start": 2012, "schumpeter_layer": "meso", "key_researchers": ["Jeffrey Gordon", "Rob Knight"], "key_works": ["Therapeutic modulation of microbiota-host metabolic interactions (2012)"], "industry_tags": "microbiome, biotechnology, pharmaceutical", "school_of_thought": "マイクロバイオーム産業論", "innovation_type": "product,paradigm", "cognitive_mechanism": "ecosystem_thinking,translational", "keywords_en": "microbiome therapeutics, live biotherapeutics, fecal transplant, gut-brain axis", "keywords_ja": "マイクロバイオーム治療薬,生きた微生物製剤,糞便移植", "opposing_concept_names": "single-target pharmacology", "category": "D_directionality"},
    {"id": "inno_sect_253", "name_en": "Emergency Medicine Innovation Dynamics", "name_ja": "救急医療イノベーション動態", "definition": "救急医療における技術・組織・プロセスイノベーションの動態。(1)時間的制約下の意思決定、(2)多職種チームの即時的協働、(3)標準化プロトコル（ATLS等）の役割、(4)遠隔救急相談の発展。災害医療・パンデミック対応がイノベーション加速の契機となる。", "impact_summary": "時間制約型医療環境でのイノベーション特性の理解", "era_start": 2000, "schumpeter_layer": "micro", "key_researchers": ["Peter Rosen", "Judith Tintinalli"], "key_works": ["Innovation in emergency medicine (2010)"], "industry_tags": "emergency medicine, trauma care, prehospital", "school_of_thought": "救急医療システム論", "innovation_type": "process,organizational", "cognitive_mechanism": "time_critical,protocol", "keywords_en": "emergency medicine innovation, trauma system, ATLS, tele-emergency", "keywords_ja": "救急医療イノベーション,外傷システム,遠隔救急", "opposing_concept_names": "elective care innovation model", "category": "D_directionality"},
    {"id": "inno_sect_254", "name_en": "Nutraceutical Innovation Space", "name_ja": "ニュートラシューティカルイノベーション空間", "definition": "食品と医薬品の境界領域におけるイノベーション。機能性食品・サプリメント・プロバイオティクスの科学的エビデンス構築と規制枠組みの発展。製薬的アプローチ（RCT）と食品科学的アプローチの方法論的緊張関係がセクターの発展を規定。", "impact_summary": "食品・医薬品境界領域のイノベーションガバナンスの理解", "era_start": 2000, "schumpeter_layer": "meso", "key_researchers": ["Bruce German", "Mark Lucock"], "key_works": ["The state of the science on dietary supplements (2015)"], "industry_tags": "nutraceuticals, functional foods, supplements", "school_of_thought": "ニュートラシューティカル論", "innovation_type": "product,regulatory", "cognitive_mechanism": "boundary_crossing,evidence_building", "keywords_en": "nutraceutical, functional food, dietary supplement, health claim regulation", "keywords_ja": "ニュートラシューティカル,機能性食品,サプリメント,ヘルスクレーム", "opposing_concept_names": "strict food-drug binary classification", "category": "D_directionality"},
    {"id": "inno_sect_255", "name_en": "Hospital at Home Innovation", "name_ja": "在宅入院イノベーション", "definition": "急性期医療を病院ではなく患者の自宅で提供するモデルのイノベーション。遠隔モニタリング・訪問医療・モバイルラボの統合により、病院と同等の医療を在宅で実現。COVID-19が普及を加速。コスト削減・患者満足度向上・院内感染リスク回避のトリプルベネフィットが実証。", "impact_summary": "医療提供場所の脱施設化モデルの有効性実証", "era_start": 2005, "schumpeter_layer": "micro", "key_researchers": ["Bruce Leff", "David Levine"], "key_works": ["Hospital at home: feasibility and outcomes (2005)"], "industry_tags": "healthcare, home care, remote monitoring", "school_of_thought": "在宅急性期ケア論", "innovation_type": "service,organizational", "cognitive_mechanism": "decentralization,care_model", "keywords_en": "hospital at home, acute care at home, remote monitoring, care delivery innovation", "keywords_ja": "在宅入院,自宅急性期ケア,遠隔モニタリング,ケアモデル革新", "opposing_concept_names": "hospital-centric care model", "category": "D_directionality"},
    {"id": "inno_sect_256", "name_en": "Pharmaceutical Clinical Biomarker Strategy", "name_ja": "医薬品臨床バイオマーカー戦略", "definition": "バイオマーカーを活用した臨床開発戦略の革新。予測バイオマーカー・サロゲートエンドポイント・コンパニオン診断の開発により、患者選択の精緻化と開発成功率の向上を図る。FDA/EMAのバイオマーカー適格性認定プロセスとの共進化が進行。", "impact_summary": "臨床開発効率化とバイオマーカー科学の産業的応用", "era_start": 2004, "schumpeter_layer": "meso", "key_researchers": ["Janet Woodcock", "Robert Temple"], "key_works": ["Biomarkers and surrogate endpoints (2001)"], "industry_tags": "pharmaceutical, diagnostics, biomarkers", "school_of_thought": "トランスレーショナルバイオマーカー論", "innovation_type": "process,product", "cognitive_mechanism": "stratification,predictive", "keywords_en": "clinical biomarker, surrogate endpoint, companion diagnostics, patient stratification", "keywords_ja": "臨床バイオマーカー,サロゲートエンドポイント,コンパニオン診断", "opposing_concept_names": "one-size-fits-all trial design", "category": "D_directionality"},
    {"id": "inno_sect_257", "name_en": "Antibiotic Stewardship Innovation", "name_ja": "抗菌薬適正使用イノベーション", "definition": "抗菌薬の適正使用を推進する臨床的・制度的イノベーション。診断支援ツール・処方監査・教育プログラム・規制インセンティブの組み合わせによるマルチモーダルアプローチ。薬剤耐性対策としての公衆衛生的重要性と臨床現場のインセンティブ構造の整合が課題。", "impact_summary": "抗菌薬使用の最適化と薬剤耐性対策の制度設計", "era_start": 2007, "schumpeter_layer": "meso", "key_researchers": ["Brad Spellberg", "Dilip Nathwani"], "key_works": ["Antimicrobial stewardship: systems-based approach (2014)"], "industry_tags": "healthcare, antimicrobials, infection control", "school_of_thought": "抗菌薬スチュワードシップ論", "innovation_type": "process,institutional", "cognitive_mechanism": "behavioral,systemic", "keywords_en": "antibiotic stewardship, AMR, prescribing guidelines, diagnostic stewardship", "keywords_ja": "抗菌薬適正使用,AMR,処方ガイドライン,診断スチュワードシップ", "opposing_concept_names": "unrestricted antibiotic access", "category": "D_directionality"},
    {"id": "inno_sect_258", "name_en": "Digital Therapeutics (DTx)", "name_ja": "デジタル治療薬（DTx）", "definition": "ソフトウェアベースの治療介入（アプリ等）が従来の医薬品と同等の規制承認・臨床エビデンス・保険償還を獲得する新カテゴリー。Pear TherapeuticsのreSET（薬物依存）・Akili InteractiveのEndeavorRx（ADHD）等が先駆例。医薬品とデジタルプロダクトの融合による新セクター形成。", "impact_summary": "ソフトウェア治療薬という新カテゴリーの制度的確立", "era_start": 2017, "schumpeter_layer": "meso", "key_researchers": ["Corey McCann", "Eddie Martucci"], "key_works": ["Digital therapeutics: preparing for a new era (2020)"], "industry_tags": "digital therapeutics, software, pharmaceutical", "school_of_thought": "デジタル治療薬論", "innovation_type": "product,paradigm", "cognitive_mechanism": "category_creation,convergence", "keywords_en": "digital therapeutics, DTx, software as medical device, prescription digital therapy", "keywords_ja": "デジタル治療薬,DTx,プログラム医療機器", "opposing_concept_names": "molecule-based therapeutics only", "category": "D_directionality"},
    {"id": "inno_sect_259", "name_en": "Pandemic Preparedness Innovation System", "name_ja": "パンデミック準備イノベーションシステム", "definition": "感染症パンデミックへの備えとしてのイノベーション体制。CEPI・BARDA等の公的資金メカニズム、100日ミッション（100 Days Mission）、mRNAプラットフォーム技術、製造キャパシティ予約等の制度・技術・組織的革新の統合。COVID-19経験が抜本的な制度改革を駆動。", "impact_summary": "パンデミック対応のイノベーションシステム再設計", "era_start": 2015, "schumpeter_layer": "macro", "key_researchers": ["Richard Hatchett", "Seth Berkley"], "key_works": ["100 Days Mission (2021)", "CEPI strategic plan"], "industry_tags": "vaccines, pandemic preparedness, public health", "school_of_thought": "パンデミック準備論", "innovation_type": "systemic,institutional", "cognitive_mechanism": "preparedness,mission_oriented", "keywords_en": "pandemic preparedness, CEPI, 100 Days Mission, platform technology, surge manufacturing", "keywords_ja": "パンデミック準備,CEPI,100日ミッション,プラットフォーム技術", "opposing_concept_names": "reactive pandemic response", "category": "D_directionality"},
    {"id": "inno_sect_260", "name_en": "Rehabilitation Technology Innovation", "name_ja": "リハビリテーション技術イノベーション", "definition": "リハビリテーション領域における技術革新。ロボットスーツ（HAL等）・VRリハビリ・ブレイン-マシンインターフェース・装具のデジタル化が機能回復の可能性を拡大。神経可塑性の科学的理解進展が技術開発を駆動。高齢化社会における需要拡大がセクター成長を加速。", "impact_summary": "リハビリテーション技術革新による機能回復の新可能性", "era_start": 2005, "schumpeter_layer": "meso", "key_researchers": ["Yoshiyuki Sankai", "José del R. Millán"], "key_works": ["HAL: hybrid assistive limb (2004)"], "industry_tags": "rehabilitation, robotics, assistive technology", "school_of_thought": "リハビリテーション工学", "innovation_type": "product,process", "cognitive_mechanism": "neuroplasticity,human_machine", "keywords_en": "rehabilitation technology, robotic rehabilitation, VR therapy, brain-machine interface", "keywords_ja": "リハビリ技術,ロボットリハビリ,VR療法,ブレインマシンインターフェース", "opposing_concept_names": "manual therapy only approach", "category": "D_directionality"},
    {"id": "inno_sect_261", "name_en": "Pharmacy Automation and Digitization", "name_ja": "薬局自動化・デジタル化", "definition": "調剤薬局における自動調剤・処方監査AI・オンライン服薬指導・電子お薬手帳等のデジタル変革。薬剤師の役割を調剤作業から臨床薬学（薬物治療管理）へとシフトさせる構造変革。日本の医薬分業制度・門前薬局構造が変革の方向性を規定。", "impact_summary": "薬局セクターのデジタル変革と薬剤師役割の再定義", "era_start": 2010, "schumpeter_layer": "meso", "key_researchers": ["Stephen Schondelmeyer", "Nabil Khalidi"], "key_works": ["Pharmacy automation and technology (2015)"], "industry_tags": "pharmacy, automation, digital health", "school_of_thought": "薬局DX論", "innovation_type": "process,service", "cognitive_mechanism": "automation,role_shift", "keywords_en": "pharmacy automation, e-prescription, medication management, pharmacist role evolution", "keywords_ja": "薬局自動化,電子処方箋,服薬管理,薬剤師役割進化", "opposing_concept_names": "traditional dispensing-focused pharmacy", "category": "D_directionality"},
    {"id": "inno_sect_262", "name_en": "Companion Animal Healthcare Innovation", "name_ja": "コンパニオンアニマル医療イノベーション", "definition": "ペット医療（犬・猫等）のイノベーション動態。ヒト医療技術の応用・ペット保険普及・飼い主の支出意向上昇により急速に高度化。がん治療・再生医療・ゲノム診断のペット応用が進行。One Health概念の実践としてヒト医療との技術移転が双方向化。", "impact_summary": "コンパニオンアニマル医療セクターの急速な高度化メカニズム", "era_start": 2010, "schumpeter_layer": "meso", "key_researchers": ["Matthew Breen", "Jaime Modiano"], "key_works": ["One Medicine: comparative medicine (2016)"], "industry_tags": "veterinary medicine, pet healthcare, animal health", "school_of_thought": "コンパニオンアニマル医療論", "innovation_type": "product,service", "cognitive_mechanism": "technology_transfer,one_health", "keywords_en": "companion animal healthcare, veterinary innovation, One Health, pet insurance", "keywords_ja": "コンパニオンアニマル医療,獣医イノベーション,ワンヘルス,ペット保険", "opposing_concept_names": "basic veterinary care model", "category": "D_directionality"},
    {"id": "inno_sect_263", "name_en": "Radiation Therapy Technology Evolution", "name_ja": "放射線治療技術進化", "definition": "放射線治療の技術的進化軌道。3D-CRT→IMRT→IGRT→粒子線治療→FLASH放射線療法と累積的に高精度化が進行。大型加速器の小型化・AI治療計画の実装が普及を加速。高い資本集約性と専門技能要求がセクター構造を規定。", "impact_summary": "放射線治療セクターの累積的技術進化パターンの理解", "era_start": 1990, "schumpeter_layer": "meso", "key_researchers": ["Sten Nilsson", "C. Clifton Ling"], "key_works": ["Intensity-modulated radiation therapy: the state of the art (2003)"], "industry_tags": "radiation therapy, oncology, medical devices", "school_of_thought": "放射線治療技術論", "innovation_type": "product,process", "cognitive_mechanism": "cumulative,precision", "keywords_en": "radiation therapy, IMRT, proton therapy, FLASH radiation, AI treatment planning", "keywords_ja": "放射線治療,IMRT,粒子線治療,FLASH放射線,AI治療計画", "opposing_concept_names": "conventional radiation techniques", "category": "D_directionality"},
    {"id": "inno_sect_264", "name_en": "Long-Acting Injectable Innovation", "name_ja": "長時間作用型注射剤イノベーション", "definition": "月1回・隔月・年1回投与の長時間作用型注射剤による服薬アドヒアランス問題の解決。HIV予防・精神疾患・避妊等の領域で普及。ナノ粒子技術・生分解性ポリマー・インプラント技術の融合。患者の利便性向上と治療効果の安定化を両立。", "impact_summary": "服薬アドヒアランス問題への技術的解決アプローチ", "era_start": 2010, "schumpeter_layer": "meso", "key_researchers": ["Giovanni Traverso", "Robert Langer"], "key_works": ["Long-acting injectable formulations (2019)"], "industry_tags": "pharmaceutical, drug delivery, formulation", "school_of_thought": "薬物送達システム論", "innovation_type": "product,process", "cognitive_mechanism": "sustained_release,patient_compliance", "keywords_en": "long-acting injectable, adherence, nanoparticle, sustained release, implant", "keywords_ja": "長時間作用型注射剤,アドヒアランス,ナノ粒子,徐放", "opposing_concept_names": "daily oral medication model", "category": "D_directionality"},
    {"id": "inno_sect_265", "name_en": "Healthcare Interoperability Standards", "name_ja": "医療相互運用性標準", "definition": "異なる医療情報システム間のデータ交換標準（HL7 FHIR・DICOM・IHE等）のイノベーション。技術標準の策定・実装・普及プロセスが医療DXの基盤。標準化の進展が新たなサービスイノベーション（PHR・AI診断等）の前提条件を形成。", "impact_summary": "医療データ相互運用性が可能にするセクターイノベーション", "era_start": 2012, "schumpeter_layer": "meso", "key_researchers": ["Grahame Grieve", "Micky Tripathi"], "key_works": ["FHIR: fast healthcare interoperability resources (2014)"], "industry_tags": "health IT, standards, interoperability", "school_of_thought": "医療情報標準論", "innovation_type": "infrastructure,institutional", "cognitive_mechanism": "standardization,network_effect", "keywords_en": "healthcare interoperability, FHIR, HL7, DICOM, health data exchange", "keywords_ja": "医療相互運用性,FHIR,HL7,DICOM,医療データ交換", "opposing_concept_names": "proprietary health IT systems", "category": "D_directionality"},
    {"id": "inno_sect_266", "name_en": "Synthetic Biology in Healthcare", "name_ja": "合成生物学の医療応用", "definition": "生物学的部品の設計・構築・再構成による新たな治療法・診断法の創出。遺伝子回路設計・細胞工場・人工臓器・合成ワクチンの開発。DIY bio・iGEM等のオープンサイエンス文化とバイオセキュリティの緊張関係。バイオファウンドリーの産業化が進行。", "impact_summary": "合成生物学による医療イノベーションの新たなフロンティア", "era_start": 2010, "schumpeter_layer": "meso", "key_researchers": ["Drew Endy", "Jim Collins", "George Church"], "key_works": ["Synthetic biology: engineering explored (2010)"], "industry_tags": "synthetic biology, biotechnology, therapeutics", "school_of_thought": "合成生物学応用論", "innovation_type": "product,paradigm", "cognitive_mechanism": "engineering_biology,design", "keywords_en": "synthetic biology, gene circuits, biofoundry, engineered cells, biosecurity", "keywords_ja": "合成生物学,遺伝子回路,バイオファウンドリー,細胞工学", "opposing_concept_names": "natural product-based medicine", "category": "D_directionality"},
    {"id": "inno_sect_267", "name_en": "Primary Care Innovation Models", "name_ja": "プライマリケアイノベーションモデル", "definition": "プライマリケアの提供モデル革新。Patient-Centered Medical Home・Integrated Care・チーム基盤型ケア・マイクロプラクティスの発展。慢性疾患管理の効率化・予防医療の強化・患者アクセスの改善を同時に追求。支払制度改革（capitation等）との連動が鍵。", "impact_summary": "プライマリケア提供モデルの構造変革と質改善", "era_start": 2005, "schumpeter_layer": "micro", "key_researchers": ["Barbara Starfield", "Thomas Bodenheimer"], "key_works": ["Primary care: balancing health needs, services, and technology (1998)"], "industry_tags": "primary care, community health, chronic disease", "school_of_thought": "プライマリケア革新論", "innovation_type": "service,organizational", "cognitive_mechanism": "care_model,team_based", "keywords_en": "primary care innovation, PCMH, integrated care, team-based care, capitation", "keywords_ja": "プライマリケア革新,PCMH,統合ケア,チーム医療", "opposing_concept_names": "specialist-driven care model", "category": "D_directionality"},
    {"id": "inno_sect_268", "name_en": "Biobank and Research Infrastructure", "name_ja": "バイオバンクと研究インフラ", "definition": "大規模生体試料バンク（UK Biobank・BBJ等）が精密医療・ゲノム研究・疫学の基盤インフラとして機能するイノベーション支援構造。50万人規模の前向きコホートが長期的研究資源として産業・学術のイノベーションを支える。データ共有・ガバナンス・持続可能性の制度設計が重要。", "impact_summary": "生体試料データインフラがセクターイノベーションを加速する構造", "era_start": 2006, "schumpeter_layer": "meso", "key_researchers": ["Rory Collins", "Mark Caulfield"], "key_works": ["UK Biobank: an open access resource (2015)"], "industry_tags": "biobanking, genomics, research infrastructure", "school_of_thought": "研究インフラ論", "innovation_type": "infrastructure,institutional", "cognitive_mechanism": "platform,resource_sharing", "keywords_en": "biobank, UK Biobank, research infrastructure, genomic data, cohort study", "keywords_ja": "バイオバンク,UK Biobank,研究インフラ,ゲノムデータ", "opposing_concept_names": "small-scale fragmented research", "category": "D_directionality"},
    {"id": "inno_sect_269", "name_en": "Surgical Robotics Innovation", "name_ja": "手術ロボットイノベーション", "definition": "da Vinci System（Intuitive Surgical）に代表される手術支援ロボットの技術・市場・制度的進化。低侵襲手術の精度向上・術者の学習曲線短縮・遠隔手術の可能性。プラットフォーム独占→競争参入（Medtronic Hugo等）の産業動態。高い資本コストと利用効率の経済的課題。", "impact_summary": "手術ロボット産業の形成と競争構造変化の理解", "era_start": 2000, "schumpeter_layer": "meso", "key_researchers": ["Myriam Curet", "Yulun Wang"], "key_works": ["Robotic surgery: history, current status, and future directions (2015)"], "industry_tags": "surgical robotics, medical devices, minimally invasive surgery", "school_of_thought": "手術ロボット産業論", "innovation_type": "product,process", "cognitive_mechanism": "platform_monopoly,precision", "keywords_en": "surgical robotics, da Vinci, minimally invasive, tele-surgery, robotic platform", "keywords_ja": "手術ロボット,ダヴィンチ,低侵襲手術,遠隔手術", "opposing_concept_names": "conventional open surgery", "category": "D_directionality"},
    {"id": "inno_sect_270", "name_en": "Blood Transfusion Innovation", "name_ja": "輸血イノベーション", "definition": "輸血医療の技術・安全性・供給チェーンイノベーション。病原体不活化技術・人工血液（ヘモグロビンベース酸素運搬体）・iPS由来血小板・自動血液型判定・在庫最適化AIの発展。高齢化による需給ギャップが代替技術開発を駆動。", "impact_summary": "輸血医療の安全性向上と代替技術開発の動態", "era_start": 2005, "schumpeter_layer": "meso", "key_researchers": ["Harvey Klein", "Koji Eto"], "key_works": ["Alternatives to blood transfusion in transfusion medicine (2017)"], "industry_tags": "transfusion medicine, blood products, hematology", "school_of_thought": "輸血医学イノベーション論", "innovation_type": "product,process", "cognitive_mechanism": "safety,substitution", "keywords_en": "blood transfusion innovation, pathogen inactivation, artificial blood, iPS platelets", "keywords_ja": "輸血イノベーション,病原体不活化,人工血液,iPS血小板", "opposing_concept_names": "conventional donor-dependent transfusion", "category": "D_directionality"},
    {"id": "inno_sect_271", "name_en": "Ophthalmology Innovation Dynamics", "name_ja": "眼科イノベーション動態", "definition": "眼科領域の技術革新動態。LASIK→フェムト秒レーザー→抗VEGF療法→遺伝子治療（Luxturna）と多方向に進化。AI網膜画像診断・スマートコンタクトレンズの新興技術。診断・治療・光学矯正の3軸でイノベーションが並行進行。", "impact_summary": "眼科セクターの多軸的イノベーション進化パターン", "era_start": 2000, "schumpeter_layer": "meso", "key_researchers": ["Jean Bennett", "Robert Machemer"], "key_works": ["Gene therapy for inherited retinal diseases (2017)"], "industry_tags": "ophthalmology, optical devices, gene therapy", "school_of_thought": "眼科技術進化論", "innovation_type": "product,process", "cognitive_mechanism": "multi_trajectory,precision", "keywords_en": "ophthalmology innovation, LASIK, anti-VEGF, retinal gene therapy, AI retinal screening", "keywords_ja": "眼科イノベーション,LASIK,抗VEGF,網膜遺伝子治療,AI網膜スクリーニング", "opposing_concept_names": "conventional corrective approach", "category": "D_directionality"},
    {"id": "inno_sect_272", "name_en": "Health Workforce Innovation", "name_ja": "医療人材イノベーション", "definition": "医療従事者の教育・訓練・配置・スキルミックスに関するイノベーション。タスクシフティング・シミュレーション教育・AIスキル補完・遠隔指導の発展により、人材不足と技能格差への構造的対応を図る。特にグローバルサウスでの人材イノベーションが重要。", "impact_summary": "医療人材の質的・量的課題に対するイノベーション解決策", "era_start": 2006, "schumpeter_layer": "meso", "key_researchers": ["Lincoln Chen", "Julio Frenk"], "key_works": ["Human resources for health: overcoming the crisis (2004)"], "industry_tags": "healthcare workforce, medical education, training", "school_of_thought": "医療人材イノベーション論", "innovation_type": "organizational,process", "cognitive_mechanism": "task_shifting,skill_augmentation", "keywords_en": "health workforce innovation, task shifting, simulation training, AI augmentation", "keywords_ja": "医療人材イノベーション,タスクシフティング,シミュレーション教育", "opposing_concept_names": "traditional physician-centric staffing", "category": "D_directionality"},
    {"id": "inno_sect_273", "name_en": "Antibody Drug Conjugate Innovation", "name_ja": "抗体薬物複合体イノベーション", "definition": "抗体に細胞毒性薬物を結合させた標的治療薬（ADC）の技術進化。Kadcyla（2013）以降、リンカー技術・ペイロード多様化・抗体工学の進歩により第3世代ADC（Enhertu等）が高い臨床効果を実証。がん治療の新たな柱として急速に市場拡大。", "impact_summary": "ADC技術の世代進化とがん治療への影響", "era_start": 2013, "schumpeter_layer": "meso", "key_researchers": ["Puja Sapra", "Akihiro Ogitani"], "key_works": ["Antibody-drug conjugates in clinical trials: current status (2019)"], "industry_tags": "pharmaceutical, oncology, biotechnology", "school_of_thought": "ADC技術進化論", "innovation_type": "product,process", "cognitive_mechanism": "targeted,conjugation", "keywords_en": "antibody drug conjugate, ADC, targeted therapy, linker technology, Enhertu", "keywords_ja": "抗体薬物複合体,ADC,標的治療,リンカー技術", "opposing_concept_names": "untargeted chemotherapy", "category": "D_directionality"},
    {"id": "inno_sect_274", "name_en": "Palliative Care Innovation", "name_ja": "緩和ケアイノベーション", "definition": "終末期・慢性疾患における緩和ケアの統合モデルイノベーション。早期からの緩和ケア統合・テレパリアティブケア・AI症状管理・アドバンスケアプランニングのデジタル化。医療費抑制と患者QOL向上の両立を示すエビデンスが蓄積。", "impact_summary": "緩和ケアの医療システム統合とデジタル革新", "era_start": 2010, "schumpeter_layer": "micro", "key_researchers": ["Jennifer Temel", "Diane Meier"], "key_works": ["Early palliative care for patients with metastatic NSCLC (2010)"], "industry_tags": "palliative care, hospice, chronic disease", "school_of_thought": "緩和ケアイノベーション論", "innovation_type": "service,organizational", "cognitive_mechanism": "integration,patient_centered", "keywords_en": "palliative care innovation, tele-palliative, advance care planning, early integration", "keywords_ja": "緩和ケアイノベーション,テレパリアティブ,ACP,早期統合", "opposing_concept_names": "curative-only treatment paradigm", "category": "D_directionality"},
    {"id": "inno_sect_275", "name_en": "RNA Therapeutics Beyond mRNA", "name_ja": "mRNA以外のRNA治療薬", "definition": "siRNA（パチシラン/Onpattro）・ASO（ヌシネルセン/Spinraza）・miRNA等のRNA治療薬プラットフォームの発展。遺伝子発現調節の精密制御により、従来undruggable（創薬困難）とされた標的への治療アプローチを開拓。delivery技術が実用化の鍵。", "impact_summary": "RNA治療薬による創薬空間の拡大と新産業形成", "era_start": 2006, "schumpeter_layer": "meso", "key_researchers": ["Alnylam Pharmaceuticals team", "Adrian Krainer"], "key_works": ["RNA therapeutics: beyond RNA interference and antisense oligonucleotides (2019)"], "industry_tags": "RNA therapeutics, biotechnology, pharmaceutical", "school_of_thought": "RNA治療薬プラットフォーム論", "innovation_type": "product,platform", "cognitive_mechanism": "platform,precision_targeting", "keywords_en": "RNA therapeutics, siRNA, antisense oligonucleotide, gene silencing, delivery", "keywords_ja": "RNA治療薬,siRNA,アンチセンスオリゴ,遺伝子サイレンシング", "opposing_concept_names": "small molecule-only pharmacology", "category": "D_directionality"},
    {"id": "inno_sect_276", "name_en": "Laboratory Automation Revolution", "name_ja": "臨床検査自動化革命", "definition": "臨床検査室の大規模自動化・ロボット化による検体処理効率の飛躍的向上。プレアナリティカル→アナリティカル→ポストアナリティカル工程の完全自動化、AI品質管理、POCT（ポイントオブケアテスト）との分散型ネットワーク構築。規模の経済と迅速性の両立。", "impact_summary": "臨床検査セクターの生産性革命と検査医学の変革", "era_start": 2005, "schumpeter_layer": "meso", "key_researchers": ["James Boyd", "Michael Laposata"], "key_works": ["Total laboratory automation (2007)"], "industry_tags": "clinical laboratory, diagnostics, automation", "school_of_thought": "臨床検査自動化論", "innovation_type": "process,organizational", "cognitive_mechanism": "automation,scale", "keywords_en": "laboratory automation, total lab automation, POCT, robotic sample handling", "keywords_ja": "臨床検査自動化,全自動検査室,POCT,ロボット検体処理", "opposing_concept_names": "manual laboratory workflow", "category": "D_directionality"},
    {"id": "inno_sect_277", "name_en": "Dermatology AI Innovation", "name_ja": "皮膚科AIイノベーション", "definition": "皮膚画像のAI自動診断技術。深層学習モデルが皮膚科医と同等以上の精度でメラノーマ・皮膚がん等を識別。スマートフォンカメラを活用した遠隔スクリーニングの可能性。専門医不足地域でのアクセス改善と医療の民主化への貢献。AI規制・医師の説明責任が制度的課題。", "impact_summary": "AI画像診断の臨床実装における先駆的事例としての皮膚科", "era_start": 2017, "schumpeter_layer": "meso", "key_researchers": ["Andre Esteva", "Holger Haenssle"], "key_works": ["Dermatologist-level classification of skin cancer with deep neural networks (2017)"], "industry_tags": "dermatology, AI diagnostics, telemedicine", "school_of_thought": "AI医療診断論", "innovation_type": "product,process", "cognitive_mechanism": "deep_learning,visual_recognition", "keywords_en": "dermatology AI, skin cancer detection, deep learning, teledermatology", "keywords_ja": "皮膚科AI,皮膚がん検出,深層学習,遠隔皮膚科", "opposing_concept_names": "clinical examination-only diagnosis", "category": "D_directionality"},
    {"id": "inno_sect_278", "name_en": "Operating Room Integration Innovation", "name_ja": "手術室統合イノベーション", "definition": "手術室のデジタル統合・ネットワーク化によるワークフロー最適化。術中ナビゲーション・画像融合・チーム通信・データ収集の統合プラットフォーム。スケジューリング最適化AIによる稼働率向上。手術室は病院で最もコスト集約的な部門として効率化の投資対効果が高い。", "impact_summary": "手術室の生産性向上とデジタル統合の産業的価値", "era_start": 2008, "schumpeter_layer": "micro", "key_researchers": ["Nassir Navab", "Russell Taylor"], "key_works": ["The operating room of the future (2013)"], "industry_tags": "operating room, medical devices, hospital IT", "school_of_thought": "手術室統合論", "innovation_type": "process,organizational", "cognitive_mechanism": "integration,workflow_optimization", "keywords_en": "operating room integration, surgical navigation, OR workflow, digital OR", "keywords_ja": "手術室統合,術中ナビゲーション,手術室ワークフロー", "opposing_concept_names": "standalone device approach", "category": "D_directionality"},
    {"id": "inno_sect_279", "name_en": "Global Clinical Trial Innovation", "name_ja": "グローバル臨床試験イノベーション", "definition": "臨床試験のグローバル化に伴う構造変革。新興国サイト活用・規制調和（ICH-GCP）・多地域共同試験（MRCT）デザイン・リアルタイムデータモニタリングの発展。試験コスト・速度・多様性（diversity in clinical trials）の最適化が駆動力。", "impact_summary": "臨床試験のグローバル化がもたらす構造的変革の理解", "era_start": 2005, "schumpeter_layer": "macro", "key_researchers": ["Ken Getz", "Pierluigi Russo"], "key_works": ["Informing a global strategy for clinical research (2012)"], "industry_tags": "clinical trials, CRO, regulatory", "school_of_thought": "グローバル臨床試験論", "innovation_type": "process,institutional", "cognitive_mechanism": "globalization,harmonization", "keywords_en": "global clinical trials, ICH-GCP, multi-regional trials, diversity, emerging market sites", "keywords_ja": "グローバル臨床試験,ICH-GCP,多地域共同試験,多様性", "opposing_concept_names": "single-country trial model", "category": "D_directionality"},
    {"id": "inno_sect_280", "name_en": "Health System Learning Innovation", "name_ja": "学習する医療システム", "definition": "ルーチンの臨床データを継続的に学習・改善に活用する医療システムの構築。電子健康記録からのリアルタイム学習・品質改善サイクル・臨床実践変革の自動化。Institute of Medicine (NAM) が提唱した「Learning Health System」概念の実装。", "impact_summary": "医療システムの継続的学習・改善メカニズムの制度化", "era_start": 2007, "schumpeter_layer": "macro", "key_researchers": ["Charles Friedman", "Lynn Etheredge"], "key_works": ["A rapid-learning health system (2007)"], "industry_tags": "health systems, quality improvement, health IT", "school_of_thought": "学習型医療システム論", "innovation_type": "systemic,institutional", "cognitive_mechanism": "continuous_learning,feedback_loop", "keywords_en": "learning health system, continuous improvement, clinical data reuse, quality cycle", "keywords_ja": "学習する医療システム,継続的改善,臨床データ再利用", "opposing_concept_names": "static evidence-based practice", "category": "D_directionality"},
    {"id": "inno_sect_281", "name_en": "Maternal and Neonatal Health Innovation", "name_ja": "母子健康イノベーション", "definition": "妊産婦・新生児ケアにおける技術・サービスイノベーション。遠隔胎児モニタリング・AI産科リスク予測・新生児集中治療の進化・低リソース環境向け適正技術。周産期死亡率の地域間格差が持続する中、frugal innovationの重要性が増大。", "impact_summary": "母子健康領域のイノベーション格差と解決アプローチ", "era_start": 2005, "schumpeter_layer": "meso", "key_researchers": ["Joy Lawn", "Zulfiqar Bhutta"], "key_works": ["Every newborn: progress, priorities, and potential (2014)"], "industry_tags": "maternal health, neonatal care, global health", "school_of_thought": "周産期イノベーション論", "innovation_type": "product,service", "cognitive_mechanism": "frugal,equity_driven", "keywords_en": "maternal health innovation, neonatal care, fetal monitoring, frugal innovation", "keywords_ja": "母子健康イノベーション,新生児ケア,胎児モニタリング", "opposing_concept_names": "high-tech hospital-only care", "category": "D_directionality"},
    {"id": "inno_sect_282", "name_en": "Decentralized Clinical Trials", "name_ja": "分散型臨床試験", "definition": "治験施設に依存しない、患者中心の臨床試験モデル。ウェアラブルデバイス・遠隔診療・eConsent・直接配送（direct-to-patient）により、従来の施設来院モデルを変革。COVID-19が加速装置として機能し、規制当局のガイダンス整備が進展。参加者多様性の改善にも寄与。", "impact_summary": "臨床試験の患者中心化とアクセシビリティの革新", "era_start": 2018, "schumpeter_layer": "meso", "key_researchers": ["Craig Lipset", "Aiden O'Brien"], "key_works": ["Decentralized clinical trials: shifting the paradigm (2020)"], "industry_tags": "clinical trials, decentralized, digital health", "school_of_thought": "分散型臨床試験論", "innovation_type": "process,organizational", "cognitive_mechanism": "decentralization,patient_centric", "keywords_en": "decentralized clinical trials, DCT, virtual trials, eConsent, direct-to-patient", "keywords_ja": "分散型臨床試験,DCT,バーチャル治験,eConsent", "opposing_concept_names": "site-centric trial model", "category": "D_directionality"},
    {"id": "inno_sect_283", "name_en": "Immunotherapy Revolution in Oncology", "name_ja": "がん免疫療法革命", "definition": "免疫チェックポイント阻害薬（抗PD-1/PD-L1・抗CTLA-4）によるがん治療パラダイムの転換。2010年代のイピリムマブ・ニボルマブ・ペムブロリズマブの成功がセクター全体のR&D投資方向性を変革。併用療法・バイオマーカー同定・耐性機構の解明が次の焦点。", "impact_summary": "がん治療の第4の柱としての免疫療法の産業的インパクト", "era_start": 2011, "schumpeter_layer": "meso", "key_researchers": ["James Allison", "Tasuku Honjo"], "key_works": ["Immune checkpoint blockade in cancer therapy (2015)"], "industry_tags": "oncology, immunotherapy, pharmaceutical", "school_of_thought": "がん免疫療法産業論", "innovation_type": "product,paradigm", "cognitive_mechanism": "paradigm_shift,immune", "keywords_en": "cancer immunotherapy, checkpoint inhibitor, PD-1, CTLA-4, immuno-oncology", "keywords_ja": "がん免疫療法,チェックポイント阻害薬,PD-1,免疫腫瘍学", "opposing_concept_names": "chemotherapy-centric oncology", "category": "D_directionality"},
    {"id": "inno_sect_284", "name_en": "Pharmacovigilance Innovation", "name_ja": "医薬品安全性監視イノベーション", "definition": "医薬品市販後安全性監視のデジタル革新。自然言語処理による有害事象報告の自動解析・ソーシャルメディアモニタリング・AI信号検出・患者直接報告（patient-reported outcomes）の統合。規制要件の国際的調和（ICH E2E）とリアルタイム化が進行。", "impact_summary": "医薬品安全性監視の自動化・効率化と早期信号検出", "era_start": 2010, "schumpeter_layer": "meso", "key_researchers": ["Gerald Dal Pan", "Marie Lindquist"], "key_works": ["Pharmacovigilance in the age of big data (2018)"], "industry_tags": "pharmaceutical, pharmacovigilance, regulatory", "school_of_thought": "デジタル医薬品安全性監視論", "innovation_type": "process,product", "cognitive_mechanism": "signal_detection,NLP", "keywords_en": "pharmacovigilance, adverse event detection, NLP, social media monitoring, real-time safety", "keywords_ja": "医薬品安全性監視,有害事象検出,NLP,リアルタイム安全性", "opposing_concept_names": "manual adverse event reporting", "category": "D_directionality"},
    {"id": "inno_sect_285", "name_en": "CRISPR Therapeutic Applications", "name_ja": "CRISPRの治療応用", "definition": "CRISPR-Cas9遺伝子編集技術の治療応用。Casgevy（鎌状赤血球病/βサラセミア、2023年承認）が最初の承認例。ex vivo編集（造血幹細胞）からin vivo編集（肝臓・眼・筋肉等）への発展。安全性・効率性・デリバリー・倫理的問題が産業化の論点。", "impact_summary": "遺伝子編集治療の産業化と倫理的ガバナンスの課題", "era_start": 2012, "schumpeter_layer": "meso", "key_researchers": ["Jennifer Doudna", "Emmanuelle Charpentier", "Feng Zhang"], "key_works": ["A programmable dual-RNA-guided DNA endonuclease (2012)"], "industry_tags": "gene editing, CRISPR, biotechnology", "school_of_thought": "遺伝子編集治療論", "innovation_type": "product,paradigm", "cognitive_mechanism": "precision_editing,transformative", "keywords_en": "CRISPR therapeutics, gene editing, Casgevy, in vivo editing, off-target effects", "keywords_ja": "CRISPR治療,遺伝子編集,Casgevy,in vivo編集", "opposing_concept_names": "conventional gene therapy vectors", "category": "D_directionality"},
    {"id": "inno_sect_286", "name_en": "Hospital Supply Chain Innovation", "name_ja": "病院サプライチェーンイノベーション", "definition": "病院の医療材料・医薬品調達・在庫管理のデジタル革新。RFIDトラッキング・自動補充システム・GPO（Group Purchasing Organization）戦略・需要予測AI。COVID-19で顕在化したサプライチェーン脆弱性への対応としてレジリエンス強化が優先課題に。", "impact_summary": "病院運営のサプライチェーン効率化とレジリエンス向上", "era_start": 2008, "schumpeter_layer": "micro", "key_researchers": ["Eugene Schneller", "Larry Smeltzer"], "key_works": ["Strategic management of the health care supply chain (2006)"], "industry_tags": "hospital operations, supply chain, logistics", "school_of_thought": "医療サプライチェーン管理論", "innovation_type": "process,organizational", "cognitive_mechanism": "optimization,resilience", "keywords_en": "hospital supply chain, GPO, RFID tracking, demand forecasting, resilience", "keywords_ja": "病院サプライチェーン,GPO,RFIDトラッキング,需要予測", "opposing_concept_names": "manual procurement process", "category": "D_directionality"},
    {"id": "inno_sect_287", "name_en": "Liquid Biopsy Innovation", "name_ja": "リキッドバイオプシーイノベーション", "definition": "血液等の体液から腫瘍由来DNA（ctDNA）・循環腫瘍細胞（CTC）・エクソソームを検出する非侵襲的がん診断技術。組織生検の限界を克服し、治療モニタリング・早期発見・微小残存病変の検出を可能にする。Guardant Health・GRAIL等の企業が産業化を推進。", "impact_summary": "非侵襲的がん診断の技術革新と市場形成", "era_start": 2014, "schumpeter_layer": "meso", "key_researchers": ["Bert Vogelstein", "Dennis Lo"], "key_works": ["Circulating tumor DNA as liquid biopsy (2016)"], "industry_tags": "diagnostics, oncology, genomics", "school_of_thought": "リキッドバイオプシー論", "innovation_type": "product,process", "cognitive_mechanism": "non_invasive,molecular", "keywords_en": "liquid biopsy, ctDNA, circulating tumor cells, early cancer detection, GRAIL", "keywords_ja": "リキッドバイオプシー,ctDNA,循環腫瘍細胞,早期がん検出", "opposing_concept_names": "tissue biopsy-only approach", "category": "D_directionality"},
    {"id": "inno_sect_288", "name_en": "Dental Implant Innovation System", "name_ja": "歯科インプラントイノベーションシステム", "definition": "チタンインプラントの表面処理技術・3Dプリンティングカスタムインプラント・即時荷重プロトコル・デジタルワークフロー統合による歯科インプラントの技術進化。材料科学・デジタル技術・臨床プロトコルの三位一体的革新。グローバル市場の成長と価格競争の激化。", "impact_summary": "歯科インプラントセクターの技術・市場・制度的進化", "era_start": 2000, "schumpeter_layer": "meso", "key_researchers": ["Per-Ingvar Brånemark", "Daniel Buser"], "key_works": ["Modern implant dentistry (2013)"], "industry_tags": "dental implants, dental materials, digital dentistry", "school_of_thought": "インプラント歯科学", "innovation_type": "product,process", "cognitive_mechanism": "material_science,digital_workflow", "keywords_en": "dental implant, surface treatment, 3D printed implant, digital implantology", "keywords_ja": "歯科インプラント,表面処理,3Dプリントインプラント,デジタルインプラント学", "opposing_concept_names": "removable prosthetics approach", "category": "D_directionality"},
    {"id": "inno_sect_289", "name_en": "Global Pharmaceutical Regulation Harmonization", "name_ja": "グローバル医薬品規制調和", "definition": "ICH（医薬品規制調和国際会議）を中心とする医薬品規制の国際調和プロセス。CTD（共通技術文書）・GCP・GMPの国際標準化がグローバル開発効率を向上。一方で各国の主権・能力格差・Access vs Quality のトレードオフが持続的課題。", "impact_summary": "医薬品規制の国際調和がグローバルイノベーションを加速する構造", "era_start": 1990, "schumpeter_layer": "macro", "key_researchers": ["Lembit Rägo", "Hubert Leufkens"], "key_works": ["International Conference on Harmonisation achievements (2010)"], "industry_tags": "pharmaceutical, regulatory, international", "school_of_thought": "国際規制調和論", "innovation_type": "institutional,systemic", "cognitive_mechanism": "harmonization,standardization", "keywords_en": "ICH, regulatory harmonization, CTD, GCP, global pharmaceutical regulation", "keywords_ja": "ICH,規制調和,CTD,GCP,グローバル医薬品規制", "opposing_concept_names": "national regulatory sovereignty", "category": "D_directionality"},
    {"id": "inno_sect_290", "name_en": "Cardiology Device Innovation", "name_ja": "循環器デバイスイノベーション", "definition": "ペースメーカー・除細動器・ステント・人工心臓・経カテーテル弁置換術（TAVR）等の循環器デバイスの技術進化。小型化・生体適合性向上・リモートモニタリング統合が進行。Medtronic・Abbott・Edwards Lifesciencesによる寡占的市場構造。", "impact_summary": "循環器デバイス産業の技術進化と市場構造の理解", "era_start": 1990, "schumpeter_layer": "meso", "key_researchers": ["Alain Cribier", "Earl Bakken"], "key_works": ["Percutaneous transcatheter implantation of an aortic valve prosthesis (2002)"], "industry_tags": "cardiology, medical devices, implants", "school_of_thought": "循環器デバイス産業論", "innovation_type": "product,process", "cognitive_mechanism": "miniaturization,biocompatibility", "keywords_en": "cardiology devices, TAVR, pacemaker, stent, remote monitoring, implantable", "keywords_ja": "循環器デバイス,TAVR,ペースメーカー,ステント,遠隔モニタリング", "opposing_concept_names": "open-heart surgery approach", "category": "D_directionality"},
    {"id": "inno_sect_291", "name_en": "Mental Health Digital Therapeutics", "name_ja": "精神医療デジタル治療", "definition": "認知行動療法（CBT）ベースのデジタルアプリによる精神疾患治療。不安障害・うつ病・PTSD・不眠症等への治療効果がRCTで実証。Woebot・SilverCloud等のAIチャットボット療法。精神科医不足への構造的解決策としてスケーラビリティの高さが評価。", "impact_summary": "精神医療のスケーラブルなデジタル解決策の実証と普及", "era_start": 2015, "schumpeter_layer": "meso", "key_researchers": ["Alison Darcy", "Gerhard Andersson"], "key_works": ["Internet-delivered psychological treatments (2014)"], "industry_tags": "mental health, digital therapeutics, AI chatbot", "school_of_thought": "デジタル精神医療論", "innovation_type": "product,service", "cognitive_mechanism": "scalable,AI_augmented", "keywords_en": "mental health DTx, digital CBT, AI chatbot therapy, internet-delivered treatment", "keywords_ja": "精神医療DTx,デジタルCBT,AIチャットボット療法", "opposing_concept_names": "face-to-face therapy only", "category": "D_directionality"},
    {"id": "inno_sect_292", "name_en": "Health Equity Innovation Framework", "name_ja": "健康公平性イノベーション枠組み", "definition": "健康格差是正を目的とするイノベーションの枠組み。社会的決定要因への介入・コミュニティヘルスワーカー活用・文化的に適切な介入デザイン・構造的人種差別への対処。従来のイノベーションが格差を拡大しうるという批判的視点が重要。", "impact_summary": "イノベーションの公平性への影響を評価・改善する分析枠組み", "era_start": 2010, "schumpeter_layer": "macro", "key_researchers": ["Michael Marmot", "David Williams"], "key_works": ["Social determinants of health and innovation (2015)"], "industry_tags": "public health, health equity, community health", "school_of_thought": "健康公平性論", "innovation_type": "institutional,service", "cognitive_mechanism": "equity_focused,structural", "keywords_en": "health equity, social determinants, health disparities, community health worker", "keywords_ja": "健康公平性,社会的決定要因,健康格差,コミュニティヘルスワーカー", "opposing_concept_names": "technology-neutral innovation approach", "category": "D_directionality"},
    {"id": "inno_sect_293", "name_en": "Fertility Technology Innovation", "name_ja": "生殖技術イノベーション", "definition": "体外受精（IVF）・着床前遺伝学的検査（PGT）・卵子凍結・AI胚選別等の生殖医療技術革新。技術的進歩と倫理的・法的・社会的影響（ELSI）の緊張関係がセクター固有の動態を形成。商業化と規制の国際的多様性が医療ツーリズムを生む。", "impact_summary": "生殖技術セクターの技術・倫理・市場の三重動態の理解", "era_start": 2000, "schumpeter_layer": "meso", "key_researchers": ["Alan Handyside", "Santiago Munné"], "key_works": ["IVF in the age of genomics (2018)"], "industry_tags": "fertility, reproductive medicine, genomics", "school_of_thought": "生殖技術イノベーション論", "innovation_type": "product,process", "cognitive_mechanism": "ELSI,technological_frontier", "keywords_en": "fertility technology, IVF, PGT, egg freezing, AI embryo selection", "keywords_ja": "生殖技術,IVF,PGT,卵子凍結,AI胚選別", "opposing_concept_names": "natural conception advocacy", "category": "D_directionality"},
    {"id": "inno_sect_294", "name_en": "Organ Transplant Innovation", "name_ja": "臓器移植イノベーション", "definition": "臓器移植のドナー拡大・保存技術・免疫抑制戦略の革新。機械灌流保存（normothermic/hypothermic）、異種移植（xenotransplantation）、バイオエンジニアード臓器の開発。慢性的ドナー不足が代替技術開発の強い動機付け。", "impact_summary": "臓器移植の技術的限界拡大と代替アプローチの探索", "era_start": 2005, "schumpeter_layer": "meso", "key_researchers": ["David Cooper", "Peter Friend"], "key_works": ["Machine perfusion of organs (2015)"], "industry_tags": "transplantation, organ preservation, xenotransplant", "school_of_thought": "移植医療イノベーション論", "innovation_type": "product,process", "cognitive_mechanism": "barrier_extension,substitution", "keywords_en": "organ transplant, machine perfusion, xenotransplantation, bioengineered organ", "keywords_ja": "臓器移植,機械灌流保存,異種移植,バイオエンジニアード臓器", "opposing_concept_names": "conventional cold storage preservation", "category": "D_directionality"},
    {"id": "inno_sect_295", "name_en": "Pediatric Drug Development Innovation", "name_ja": "小児薬開発イノベーション", "definition": "小児用医薬品開発の構造的課題とその解決策。倫理的制約・小規模患者集団・製剤開発の特殊性・規制インセンティブ（PREA・小児用医薬品法等）が形成するセクター固有の動態。成人薬の小児への外挿・モデリング&シミュレーションの活用が発展。", "impact_summary": "小児用医薬品開発の促進メカニズムと残存課題", "era_start": 2003, "schumpeter_layer": "meso", "key_researchers": ["Daniel Benjamin", "Mark Turner"], "key_works": ["Pediatric drug development: concepts and applications (2014)"], "industry_tags": "pediatric drugs, pharmaceutical, regulatory", "school_of_thought": "小児薬学", "innovation_type": "product,institutional", "cognitive_mechanism": "regulatory_incentive,extrapolation", "keywords_en": "pediatric drug development, PREA, pediatric formulation, extrapolation, M&S", "keywords_ja": "小児薬開発,PREA,小児製剤,外挿,M&S", "opposing_concept_names": "adult-only drug development", "category": "D_directionality"},
